// 包根 +esm 当前失败；在子 iframe 预声明 import map，并转义两个 script 结束标签以免截断外层 harness module
const frame = document.createElement('iframe'); frame.style.cssText = `width:100%;height:${spec.height ?? 900}px;border:0`;
const ready = new Promise(ok => frame.addEventListener('load', ok, { once: true }));
frame.srcdoc = `<script type="importmap">{"imports":{"lit":"https://cdn.jsdelivr.net/npm/lit@3/+esm","@lit/task":"https://cdn.jsdelivr.net/npm/@lit/task@1/+esm","lit/directives/choose.js":"https://cdn.jsdelivr.net/npm/lit@3/directives/choose.js/+esm","lit/directives/unsafe-html.js":"https://cdn.jsdelivr.net/npm/lit@3/directives/unsafe-html.js/+esm"}}<\/script><script type="module">import 'https://cdn.jsdelivr.net/npm/jsonresume-component@0.3.1/dist/json-resume.js';const el=document.createElement('json-resume');document.body.appendChild(el);globalThis.resumeEl=el;<\/script>`;
document.getElementById('resume').appendChild(frame); await ready;
const resumeEl = frame.contentWindow.resumeEl; if (!resumeEl) throw new Error('json-resume element failed to initialize'); resumeEl.resumejson = data.resume; resumeEl.preordered = data.preordered ?? false; if (data.label) resumeEl.label = data.label;

